mapper.select:
SELECT EXISTS (
    SELECT 1 FROM franchise WHERE manager_id = #{managerId}
)

SELECT EXISTS (
    SELECT 1 FROM franchise WHERE department_id = #{departmentId}
)

SELECT EXISTS(
    SELECT 1 FROM franchise WHERE owner_id = #{userId}
)

SELECT s.id, f.name AS franchise_name, s.year, s.month, s.return_quantity, s.created_at, s.updated_at, s.is_deleted, s.deleted_reason, s.deleted_at, s.product_id, p.name AS product_name, s.franchise_id FROM franchise_return_product_stat s JOIN franchise f ON s.franchise_id = f.id JOIN product p ON s.product_id = p.id WHERE f.manager_id = #{managerId}
AND s.year = #{year}
AND s.month = #{month}

SELECT s.id, f.name AS franchise_name, s.year, s.month, s.return_quantity, s.created_at, s.updated_at, s.is_deleted, s.deleted_reason, s.deleted_at, s.product_id, p.name AS product_name, s.franchise_id FROM franchise_return_product_stat s JOIN franchise f ON s.franchise_id = f.id JOIN product p ON s.product_id = p.id WHERE f.department_id = #{deptId}
AND s.`year` = #{year}
AND s.`month` = #{month}

SELECT s.id, f.name AS franchise_name, s.year, s.month, s.return_quantity, s.created_at, s.updated_at, s.is_deleted, s.deleted_reason, s.deleted_at, s.product_id, p.name AS product_name, s.franchise_id FROM franchise_return_product_stat s JOIN franchise f ON s.franchise_id = f.id JOIN product p ON s.product_id = p.id WHERE f.owner_id = #{userId}
AND s.year = #{year}
AND s.month = #{month}
